/**
 * AutoRelatório V5 — Cliente HTTP centralizado
 *
 * Consumo da API do backend Python (motor de geração).
 * URL base: variável de ambiente NEXT_PUBLIC_API_URL
 * fallback: http://localhost:8000 (backend FastAPI local)
 */

const BASE_URL =
  process.env.NEXT_PUBLIC_API_URL ?? 'http://localhost:8000';

// ─── Tipos de resposta do backend ────────────────────────────────────────────

export interface ApiError {
  status: number;
  message: string;
}

export interface GeneratePayload {
  contrato_id:   string;
  nr_os:         string;
  ag_cod:        string;
  ag_nome:       string;
  dt_atend:      string;
  endereco:      string;
  responsavel:   string;
  desc_index:    string;   // '1' | '2' | '3' | '4'
  modo:          string;   // 'trad' | 'sp' | 'sp2'
}

export interface GenerateResponse {
  ok:       boolean;
  filename: string;
  url:      string;   // link para download do .docx gerado
  message?: string;
}

export interface HealthResponse {
  status: 'ok' | 'degraded';
  version: string;
}

// ─── Utilitário interno ───────────────────────────────────────────────────────

async function request<T>(
  path: string,
  options?: RequestInit,
): Promise<T> {
  const res = await fetch(`${BASE_URL}${path}`, {
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    ...options,
  });

  if (!res.ok) {
    const body = await res.json().catch(() => ({}));
    const err: ApiError = {
      status:  res.status,
      message: (body as { detail?: string }).detail
               ?? `Erro ${res.status}: ${res.statusText}`,
    };
    throw err;
  }

  return res.json() as Promise<T>;
}

// ─── Endpoints públicos ───────────────────────────────────────────────────────

/** Verifica saúde do backend */
export const checkHealth = () =>
  request<HealthResponse>('/health');

/**
 * Solicita a geração do relatório .docx.
 * Backend processa e retorna URL de download.
 */
export const generateReport = (payload: GeneratePayload) =>
  request<GenerateResponse>('/generate', {
    method: 'POST',
    body:   JSON.stringify(payload),
  });
